package com.evolua.chat.interfaces.rest; import com.evolua.chat.application.MessageService; import org.springframework.messaging.handler.annotation.MessageMapping; import org.springframework.messaging.handler.annotation.Payload; import org.springframework.messaging.simp.SimpMessagingTemplate; import org.springframework.stereotype.Controller; @Controller public class ChatSocketController { private final MessageService service; private final SimpMessagingTemplate messagingTemplate; public ChatSocketController(MessageService service, SimpMessagingTemplate messagingTemplate) { this.service = service; this.messagingTemplate = messagingTemplate; } @MessageMapping("/chat.send") public void send(@Payload MessageRequest request) { var saved = service.create(request.senderId(), request.recipientId(), request.content()); messagingTemplate.convertAndSend("/topic/chat/" + request.recipientId(), saved); } public record MessageRequest(String senderId, String recipientId, String content) { } }
